		PlanFile:               data.PlanFile,
		AgentType:              data.AgentType,
		TaskNumber:             data.TaskNumber,
		WaveNumber:             data.WaveNumber,
		PeerCount:              data.PeerCount,
		IsReviewer:             data.IsReviewer,
