// InstanceData represents the serializable data of an Instance
type InstanceData struct {
	Title                  string    `json:"title"`
	Path                   string    `json:"path"`
	Branch                 string    `json:"branch"`
	Status                 Status    `json:"status"`
	Height                 int       `json:"height"`
	Width                  int       `json:"width"`
	CreatedAt              time.Time `json:"created_at"`
	UpdatedAt              time.Time `json:"updated_at"`
	AutoYes                bool      `json:"auto_yes"`
	SkipPermissions        bool      `json:"skip_permissions"`
	PlanFile               string    `json:"plan_file,omitempty"`
	AgentType              string    `json:"agent_type,omitempty"`
	TaskNumber             int       `json:"task_number,omitempty"`
	WaveNumber             int       `json:"wave_number,omitempty"`
	PeerCount              int       `json:"peer_count,omitempty"`
	IsReviewer             bool      `json:"is_reviewer,omitempty"`
	ImplementationComplete bool      `json:"implementation_complete,omitempty"`
	SoloAgent              bool      `json:"solo_agent,omitempty"`
	QueuedPrompt           string    `json:"queued_prompt,omitempty"`

	Program   string          `json:"program"`
	Worktree  GitWorktreeData `json:"worktree"`
	DiffStats DiffStatsData   `json:"diff_stats"`
}

// GitWorktreeData represents the serializable data of a GitWorktree
type GitWorktreeData struct {
	RepoPath      string `json:"repo_path"`
	WorktreePath  string `json:"worktree_path"`
	SessionName   string `json:"session_name"`
	BranchName    string `json:"branch_name"`
	BaseCommitSHA string `json:"base_commit_sha"`
}

// DiffStatsData represents the serializable data of a DiffStats
type DiffStatsData struct {
	Added   int    `json:"added"`
	Removed int    `json:"removed"`
	Content string `json:"content"`
}

// Storage handles saving and loading instances using the state interface
type Storage struct {
	state config.StateManager
}

// NewStorage creates a new storage instance
func NewStorage(state config.StateManager) (*Storage, error) {
	return &Storage{
		state: state,
	}, nil
}

// SaveInstances saves the list of instances to disk
func (s *Storage) SaveInstances(instances []*Instance) error {
	// Convert instances to InstanceData
	data := make([]InstanceData, 0)
	for _, instance := range instances {
		if instance.Started() {
			data = append(data, instance.ToInstanceData())
		}
	}

	// Marshal to JSON
	jsonData, err := json.Marshal(data)
	if err != nil {
		return fmt.Errorf("failed to marshal instances: %w", err)
	}

	return s.state.SaveInstances(jsonData)
}

// LoadInstances loads the list of instances from disk
func (s *Storage) LoadInstances() ([]*Instance, error) {
	jsonData := s.state.GetInstances()

	var instancesData []InstanceData
	if err := json.Unmarshal(jsonData, &instancesData); err != nil {
		return nil, fmt.Errorf("failed to unmarshal instances: %w", err)
	}

	instances := make([]*Instance, 0, len(instancesData))
	for _, data := range instancesData {
		// Skip non-paused instances whose worktree no longer exists on disk.
		// This cleans up stale state from old sessions or config migrations
		// (e.g. worktree path was moved from ~/.config/kasmos/worktrees/ to <repo>/.worktrees/).
		if data.Status != Paused && data.Worktree.WorktreePath != "" {
			if _, err := os.Stat(data.Worktree.WorktreePath); err != nil {
				log.WarningLog.Printf("skipping stale instance %q: worktree path gone: %s",
					data.Title, data.Worktree.WorktreePath)
				continue
			}
		}
		instance, err := FromInstanceData(data)
		if err != nil {
			// Log and skip instances that fail to restore (e.g. dead tmux session)
			// instead of hard-failing, which would prevent ALL instances from loading.
			log.WarningLog.Printf("skipping unrestorable instance %q: %v", data.Title, err)
			continue
		}
		instances = append(instances, instance)
	}

	return instances, nil
}

// DeleteInstance removes an instance from storage
func (s *Storage) DeleteInstance(title string) error {
	instances, err := s.LoadInstances()
	if err != nil {
		return fmt.Errorf("failed to load instances: %w", err)
	}

	found := false
	newInstances := make([]*Instance, 0)
	for _, instance := range instances {
		data := instance.ToInstanceData()
		if data.Title != title {
			newInstances = append(newInstances, instance)
		} else {
			found = true
		}
	}

	if !found {
		return fmt.Errorf("instance not found: %s", title)
	}

	return s.SaveInstances(newInstances)
}

// UpdateInstance updates an existing instance in storage
func (s *Storage) UpdateInstance(instance *Instance) error {
	instances, err := s.LoadInstances()
	if err != nil {
		return fmt.Errorf("failed to load instances: %w", err)
	}

	data := instance.ToInstanceData()
	found := false
	for i, existing := range instances {
		existingData := existing.ToInstanceData()
		if existingData.Title == data.Title {
			instances[i] = instance
			found = true
			break
		}
	}

	if !found {
		return fmt.Errorf("instance not found: %s", data.Title)
	}

	return s.SaveInstances(instances)
}

// DeleteAllInstances removes all stored instances
func (s *Storage) DeleteAllInstances() error {
	return s.state.DeleteAllInstances()
}

